    def _deserialize_message(self, value):
        try:
            if isinstance(value, bytes):
                value = value.decode('utf-8')
            return json.loads(value)
        except (json.JSONDecodeError, UnicodeDecodeError) as e:
            self.logger.error(f"Failed to deserialize message: {e}")
            raise ValueError("Invalid message format")
            
    def _validate_message_integrity(self, message_value: Dict[str, Any], 
                                   expected_signature: str) -> bool:
        """Prevent message injection by validating signature"""
        try:
            # Extract message components for signature calculation
            message_str = json.dumps(message_value, sort_keys=True)
            expected_hash = hashlib.sha256(message_str.encode()).hexdigest()
            return hmac.compare_digest(expected_signature, expected_hash)
        except Exception:
            return False
            
